"use client";

// Weekly / monthly / yearly predictions generated by the offline engine.

import { use, useMemo, useState } from "react";
import Link from "next/link";
import { useKundli } from "@/lib/useKundli";
import { useI18n } from "@/lib/i18n";
import { AppShell } from "@/components/AppShell";
import { ProfileTheme } from "@/components/ProfileTheme";
import {
  weeklyPrediction,
  monthlyPrediction,
  yearlyPrediction,
  type Prediction,
} from "@/lib/interpret/predictions";
import { fmtDate } from "@/lib/format";

type Period = "weekly" | "monthly" | "yearly";

export default function PredictionsPage({ params }: { params: Promise<{ id: string }> }) {
  const { id } = use(params);
  const { profile, kundli, loading, error } = useKundli(Number(id));
  const { t, lang } = useI18n();
  const [period, setPeriod] = useState<Period>("weekly");

  const prediction: Prediction | null = useMemo(() => {
    if (!kundli) return null;
    if (period === "weekly") return weeklyPrediction(kundli);
    if (period === "monthly") return monthlyPrediction(kundli);
    return yearlyPrediction(kundli);
  }, [kundli, period]);

  if (loading) return <AppShell><p className="p-8 text-center text-(--color-ink-soft)">{t("loading")}</p></AppShell>;
  if (error || !kundli || !profile || !prediction) {
    return (
      <AppShell>
        <div className="card mx-auto max-w-md p-8 text-center">
          <p className="text-red-300">{error ?? t("error")}</p>
          <Link href="/" className="accent-text mt-4 inline-block text-sm underline">← {t("dashboard")}</Link>
        </div>
      </AppShell>
    );
  }

  const pick = (b: { en: string; hi: string }) => (lang === "hi" ? b.hi : b.en);
  const toneCls = {
    good: "border-emerald-500/30",
    mixed: "border-(--color-line)",
    caution: "border-orange-500/40",
  };

  const areaEntries = [
    [t("career"), prediction.areas.career],
    [t("wealth"), prediction.areas.wealth],
    [t("health"), prediction.areas.health],
    [t("relationships"), prediction.areas.relationships],
  ] as const;

  return (
    <ProfileTheme birthdayNumber={kundli.numerology.birthdayNumber}>
      <AppShell>
        <div className="mb-5 flex flex-wrap items-center justify-between gap-3">
          <div>
            <h1 className="text-xl font-semibold text-(--color-gold-soft)">
              {t("predictionFor")} {profile.name}
            </h1>
            <p className="text-xs text-(--color-ink-soft)">
              {fmtDate(prediction.rangeStart, lang)} — {fmtDate(prediction.rangeEnd, lang)} · ✓ {t("generatedOffline")}
            </p>
          </div>
          <div className="flex gap-1 rounded-lg border border-(--color-line) p-1 text-sm">
            {(["weekly", "monthly", "yearly"] as const).map((p) => (
              <button
                key={p}
                onClick={() => setPeriod(p)}
                className={`rounded-md px-4 py-1.5 transition ${
                  period === p ? "accent-bg accent-text font-medium" : "text-(--color-ink-soft)"
                }`}
              >
                {t(p)}
              </button>
            ))}
          </div>
        </div>

        <div className="card accent-border mb-5 border-l-4 p-5">
          <p className="leading-relaxed">{pick(prediction.summary)}</p>
        </div>

        {/* Area meters */}
        <div className="mb-5 grid grid-cols-2 gap-3 md:grid-cols-4">
          {areaEntries.map(([label, score]) => (
            <div key={label} className="card p-4">
              <div className="flex items-baseline justify-between">
                <span className="text-sm text-(--color-ink-soft)">{label}</span>
                <span className="text-lg font-semibold accent-text">{score}</span>
              </div>
              <div className="mt-2 h-1.5 overflow-hidden rounded-full bg-(--color-surface)">
                <div
                  className="h-full rounded-full"
                  style={{
                    width: `${score}%`,
                    background: score >= 58 ? "#4ade80" : score >= 48 ? "#fbbf24" : "#f87171",
                  }}
                />
              </div>
            </div>
          ))}
        </div>

        {period === "weekly" && (prediction.favourableDays?.length || prediction.cautionDays?.length) ? (
          <div className="mb-5 grid gap-3 md:grid-cols-2">
            {prediction.favourableDays && prediction.favourableDays.length > 0 && (
              <div className="card border-l-4 border-emerald-500/40 p-4">
                <h4 className="mb-1 text-sm font-medium text-emerald-300">{t("favourableDays")}</h4>
                <p className="text-sm">{prediction.favourableDays.join(" · ")}</p>
              </div>
            )}
            {prediction.cautionDays && prediction.cautionDays.length > 0 && (
              <div className="card border-l-4 border-orange-500/40 p-4">
                <h4 className="mb-1 text-sm font-medium text-orange-300">{t("cautionDays")}</h4>
                <p className="text-sm">{prediction.cautionDays.join(" · ")}</p>
              </div>
            )}
          </div>
        ) : null}

        <div className="space-y-3">
          {prediction.sections.map((s, i) => (
            <div key={i} className={`card border-l-4 p-5 ${toneCls[s.tone]}`}>
              <h3 className="mb-1 text-sm font-medium text-(--color-gold-soft)">{pick(s.title)}</h3>
              <p className="text-sm leading-relaxed">{pick(s.body)}</p>
            </div>
          ))}
        </div>
      </AppShell>
    </ProfileTheme>
  );
}
